package com.infy.inventrack.user.controller; import com.infy.inventrack.common.dto.*; import com.infy.inventrack.user.service.UserService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/users") public class UserController { private final UserService service; public UserController(UserService s){service=s;} @PostMapping("/register") public ResponseEntity<UserResponse> register(@Valid @RequestBody UserRegistrationRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.registerUser(r));} }
